/**
 * Tests for TransitionPicker pure utility functions
 */

import {
  formatDurationLabel,
  sliderToDuration,
  durationToSlider,
  getPresetIcon,
  buildSummaryText,
} from '@/components/editor/TransitionPicker';

import { MIN_DURATION, MAX_DURATION } from '@/lib/render/transitions';

// ============================================================================
// formatDurationLabel
// ============================================================================
describe('formatDurationLabel', () => {
  it('formats 0.5 as "0.5s"', () => {
    expect(formatDurationLabel(0.5)).toBe('0.5s');
  });

  it('formats 1.0 as "1.0s"', () => {
    expect(formatDurationLabel(1.0)).toBe('1.0s');
  });

  it('formats 2.0 as "2.0s"', () => {
    expect(formatDurationLabel(2.0)).toBe('2.0s');
  });

  it('formats 0.3 as "0.3s"', () => {
    expect(formatDurationLabel(0.3)).toBe('0.3s');
  });
});

// ============================================================================
// sliderToDuration
// ============================================================================
describe('sliderToDuration', () => {
  it('slider 0 returns MIN_DURATION', () => {
    expect(sliderToDuration(0)).toBe(MIN_DURATION);
  });

  it('slider 100 returns MAX_DURATION', () => {
    expect(sliderToDuration(100)).toBe(MAX_DURATION);
  });

  it('slider 50 returns midpoint', () => {
    const mid = sliderToDuration(50);
    expect(mid).toBeGreaterThan(MIN_DURATION);
    expect(mid).toBeLessThan(MAX_DURATION);
  });
});

// ============================================================================
// durationToSlider
// ============================================================================
describe('durationToSlider', () => {
  it('returns 0 for zero duration', () => {
    expect(durationToSlider(0)).toBe(0);
  });

  it('returns 0 for MIN_DURATION', () => {
    expect(durationToSlider(MIN_DURATION)).toBe(0);
  });

  it('returns 100 for MAX_DURATION', () => {
    expect(durationToSlider(MAX_DURATION)).toBe(100);
  });

  it('roundtrips with sliderToDuration', () => {
    const slider = 42;
    const duration = sliderToDuration(slider);
    const back = durationToSlider(duration);
    expect(back).toBe(slider);
  });
});

// ============================================================================
// getPresetIcon
// ============================================================================
describe('getPresetIcon', () => {
  it('returns a component for known icons', () => {
    expect(getPresetIcon('ban')).toBeDefined();
    expect(getPresetIcon('sun')).toBeDefined();
    expect(getPresetIcon('sparkles')).toBeDefined();
    expect(getPresetIcon('arrowLeft')).toBeDefined();
    expect(getPresetIcon('arrowRight')).toBeDefined();
    expect(getPresetIcon('zoomIn')).toBeDefined();
  });

  it('returns fallback for unknown icons', () => {
    expect(getPresetIcon('unknown')).toBeDefined();
  });
});

// ============================================================================
// buildSummaryText
// ============================================================================
describe('buildSummaryText', () => {
  it('returns "Sem transição" for none', () => {
    expect(buildSummaryText({ type: 'none', duration: 0 })).toBe('Sem transição');
  });

  it('returns label and duration for fade', () => {
    const text = buildSummaryText({ type: 'fade', duration: 0.5 });
    expect(text).toContain('Fade');
    expect(text).toContain('0.5s');
  });

  it('returns label and duration for zoom', () => {
    const text = buildSummaryText({ type: 'zoom', duration: 1.0 });
    expect(text).toContain('Zoom');
    expect(text).toContain('1.0s');
  });

  it('includes separator', () => {
    const text = buildSummaryText({ type: 'slideLeft', duration: 0.5 });
    expect(text).toContain('·');
  });
});
